long long solve(vector<long long> value, vector<long long> limit) {
    // Pair each value with its corresponding limit and sort by value in descending order
    vector<pair<long long, long long>> elements;
    for (int i = 0; i < value.size(); ++i) {
        elements.push_back({value[i], limit[i]});
    }
    sort(elements.begin(), elements.end(), greater<pair<long long, long long>>());

    // Use a priority queue to keep track of the limits of currently active elements
    priority_queue<long long> activeLimits;

    long long totalSum = 0;
    int activeCount = 0;

    for (auto& elem : elements) {
        long long val = elem.first;
        long long lim = elem.second;

        // Check if we can activate this element
        if (activeCount < lim) {
            // Activate the element
            totalSum += val;
            activeLimits.push(lim);
            activeCount++;

            // After activation, check if any elements should be deactivated
            while (!activeLimits.empty() && activeCount >= activeLimits.top()) {
                activeLimits.pop();
            }
        }
    }

    return totalSum;
}
